import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import PrivateBlockchainDevelopment from "@screens/private-blockchain-development-company";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const PrivateBlockchainDevelopmentCompany = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Private Blockchain Development Company", link: null },
  ];
  const location = useLocation();
  const { data } = props;
  const fileUrl =
    data?.privateBlockchainDevelopmentCompanyImg?.childImageSharp
      ?.gatsbyImageData?.images?.fallback?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "A private blockchain development company delivering secure, scalable networks with full control, transparency, and enterprise-grade performance.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1568",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is a private blockchain?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A private blockchain is a permission-based network where only authorized users can access, manage, and validate data, ensuring high security, privacy, and control.",
            },
          },
          {
            "@type": "Question",
            name: "Why use a private blockchain?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A private blockchain gives businesses full control, higher security, faster transactions, and better privacy, making it ideal for enterprise use.",
            },
          },
          {
            "@type": "Question",
            name: "Is a private blockchain truly decentralized?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A private blockchain is partially decentralized, as control and permissions are managed by a single organization or a limited group of participants.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        image={fileUrl}
        description={validData?.description}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <PrivateBlockchainDevelopment db={db} />
      </main>
    </Layout_v2>
  );
};

export default PrivateBlockchainDevelopmentCompany;
export const queryData = graphql`
  query MyQuery {
    privateBlockchainDevelopmentCompanyImg: file(
      relativePath: { eq: "private-blockchain-development-company.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "private-blockchain-development-company" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
